- (void)checkUpdateWithCompletion:(void (^)(BOOL found, BOOL shouldUpdate, NSDictionary * _Nullable updateInfo))completion {
    NSString *bundleId = NSBundle.mainBundle.bundleIdentifier ?: @"";
    if (bundleId.length == 0) {
        if (completion) {
            completion(NO, NO, nil);
        }
        return;
    }

    NSString *urlString = [NSString stringWithFormat:@"https://itunes.apple.com/lookup?bundleId=%@&country=cl", bundleId];
    NSURL *url = [NSURL URLWithString:urlString];

    NSURLSessionDataTask *task = [NSURLSession.sharedSession dataTaskWithURL:url completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
        if (error || !data) {
            if (completion) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    completion(NO, NO, nil);
                });
            }
            return;
        }

        id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:nil];
        NSDictionary *dict = [json isKindOfClass:[NSDictionary class]] ? json : nil;
        NSArray *results = [dict[@"results"] isKindOfClass:[NSArray class]] ? dict[@"results"] : nil;
        NSDictionary *item = results.count ? results.firstObject : nil;
        if (!item) {
            if (completion) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    completion(NO, NO, nil);
                });
            }
            return;
        }

        NSString *remoteVersion = [item[@"version"] isKindOfClass:[NSString class]] ? item[@"version"] : nil;
        NSString *localVersion = [[NSBundle mainBundle] objectForInfoDictionaryKey:@"CFBundleShortVersionString"];

        BOOL shouldUpdate = NO;
        if (remoteVersion.length && localVersion.length) {
            NSArray *rv = [remoteVersion componentsSeparatedByString:@"."];
            NSArray *lv = [localVersion componentsSeparatedByString:@"."];
            NSUInteger count = MAX(rv.count, lv.count);

            for (NSUInteger i = 0; i < count; i++) {
                NSInteger r = i < rv.count ? [rv[i] integerValue] : 0;
                NSInteger l = i < lv.count ? [lv[i] integerValue] : 0;

                if (r > l) {
                    shouldUpdate = YES;
                    break;
                }
                if (r < l) {
                    shouldUpdate = NO;
                    break;
                }
            }
        }

        dispatch_async(dispatch_get_main_queue(), ^{
            if (completion) {
                completion(YES, shouldUpdate, shouldUpdate ? item : nil);
            }
        });

