- (void)updateInviteLabel {
    NSInteger userCount = 1;
    NSNumber *dayCount = WBReferralManager.sharedManager.inviterRewardDuration;

    NSString *prefix = NSLocalizedString(@"邀请", nil);
    NSString *middle = NSLocalizedString(@"位用户", nil);
    NSString *suffix = NSLocalizedString(@"天", nil);

    NSString *userStr = [NSString stringWithFormat:@" %ld ", (long)userCount];
    NSString *dayStr = [NSString stringWithFormat:@" + %@ ", dayCount];

    NSMutableAttributedString *attrStr = [[NSMutableAttributedString alloc] init];

    UIColor *textColor = WBColorHex(0x24CF41);
    UIFont *smallFont = [UIFont systemFontOfSize:ZOOM(18) weight:UIFontWeightMedium];
    UIFont *largeFont = [UIFont systemFontOfSize:ZOOM(24) weight:UIFontWeightMedium];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:prefix attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:userStr attributes:@{
        NSFontAttributeName: largeFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:middle attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:dayStr attributes:@{
        NSFontAttributeName: largeFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:suffix attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    _toInviteLabel.attributedText = attrStr;
    _toInviteLabel.textAlignment = NSTextAlignmentNatural;
}


- (void)updateRewardsLabel {
    NSInteger reward = [WBReferralManager.sharedManager.inviterRewardDuration integerValue];
    NSInteger beginReward = [WBReferralManager.sharedManager.beginRewardDuration integerValue];
    NSInteger count = [WBReferralManager.sharedManager.rewardPaymentCount integerValue];
    NSInteger inputReward = [WBReferralManager.sharedManager.inputRewardDuration integerValue];

    NSInteger totalReward;
    if (kStringIsEmpty(WBSettingManager.sharedManager.Email) || !WBReferralManager.sharedManager.activityStart) {
        totalReward = 0;
    } else {
        totalReward = beginReward + inputReward + reward * count;
    }
    NSString *rewardText = [NSString stringWithFormat:@"%ld", (long)totalReward];
    NSString *suffix = NSLocalizedString(@"天", nil);

    NSMutableAttributedString *attrStr = [[NSMutableAttributedString alloc] init];
    UIColor *textColor = WBColorHex(0xFFFFFF);
    UIFont *smallFont = [UIFont systemFontOfSize:ZOOM(18) weight:UIFontWeightMedium];

    UIFont *largeFont = [UIFont systemFontOfSize:ZOOM(58) weight:UIFontWeightMedium];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:rewardText attributes:@{
        NSFontAttributeName: largeFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:suffix attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    self.rewardsLabel.attributedText = attrStr;
}


