#import "WBSharePopViewController.h"
#import "WBActionRequestManager.h"

@interface WBSharePopViewController ()<UIGestureRecognizerDelegate>
// 这两个属性用来实现滑动功能
@property (nonatomic, strong) UIPanGestureRecognizer *panGesture;
@property (nonatomic, assign) CGFloat initialTranslationY;// 手指开始滑动的时候的触点
@property (nonatomic, assign) CGFloat slidingTranslationY;// 手指滑动中的触点
// 在文件中添加私有变量记录初始位置
@property (assign, nonatomic) CGRect originalContainerFrame;
@end

@implementation WBSharePopViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setUpUI];
    [self setUpEvents];
}


#pragma mark - setUp

- (void)setUpUI {
    self.view.backgroundColor = RGBA(0, 0, 0, 0.2);
    self.view.alpha = 0;

    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.containerView];
    [self.containerView addSubview:self.topLineButton];
    [self.containerView addSubview:self.titleLabel];
    [self.containerView addSubview:self.shareToOthersButton];
    [self.containerView addSubview:self.shareToOthersLabel];
}

- (void)addAllConstraints {
    [self.containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.view);
        make.top.equalTo(self.view.mas_bottom);
        make.height.mas_equalTo(ZOOM(286));
    }];

    [self.topLineButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.containerView);
        make.top.equalTo(self.containerView).offset(ZOOM(10));
        make.width.mas_equalTo(ZOOM(48));
        //make.height.mas_equalTo(ZOOM(5));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.containerView);
        make.top.equalTo(self.containerView).offset(ZOOM(30));
    }];

    [self.shareToOthersButton mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.right.equalTo(self.containerView).offset(ZOOM(-63));
        } else {
            make.left.equalTo(self.containerView).offset(ZOOM(63));
        }
        make.bottom.equalTo(self.containerView.mas_bottom).offset(ZOOM(-158));
        make.width.mas_equalTo(ZOOM(40));
        make.height.mas_equalTo(ZOOM(40));
    }];

    [self.shareToOthersLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.shareToOthersButton.mas_bottom).offset(ZOOM(10));
        make.centerX.equalTo(self.shareToOthersButton);
    }];
}

- (void)setUpEvents {
    // 初始化并配置Pan Gesture Recognizer 实现滑动关闭功能
    self.panGesture = [[UIPanGestureRecognizer alloc] initWithTarget:self action:@selector(handlePanGesture:)];
    self.panGesture.delegate = self; // 设置代理以允许同时响应其他手势
    [self.containerView addGestureRecognizer:self.panGesture];

    [self.topLineButton addTarget:self action:@selector(dismiss) forControlEvents:UIControlEventTouchUpInside];
    [self.shareToOthersButton addTarget:self action:@selector(dismiss) forControlEvents:UIControlEventTouchUpInside];

    // 添加点击手势识别器到 self.view
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleTapOutside:)];
    tapGesture.cancelsTouchesInView = NO; // 不取消视图中的触摸事件，以便内部的控件可以正常响应
    [self.view addGestureRecognizer:tapGesture];
}


#pragma mark - Show Alert

+ (void)alertToShare{
    WBSharePopViewController *popVc = [[WBSharePopViewController alloc] init];
    popVc.titleLabel.text = @"分享到";
    //popVc.contentView = contentLabel;

    [popVc.shareToOthersButton addBlockForControlEvents:UIControlEventTouchUpInside block:^(id  _Nonnull sender) {
        [[WBAppManager sharedManager] shareAppByIOSShare];

    }];
    [popVc show];
}

+ (void)shareAppToOthers {
    NSString *urlString = WBSettingManager.sharedManager.ShareURL ?: @"";
    NSURLComponents *components = [NSURLComponents componentsWithString:urlString];
    if (!components) { return; }

    // 取系统当前首选语言，例如: ar-SA / en-US / zh-Hans-CN
    NSString *preferred = [NSLocale preferredLanguages].firstObject ?: @"en";
    NSString *lang = [[preferred componentsSeparatedByString:@"-"] firstObject].lowercaseString;
    if (lang.length == 0) {
        lang = @"en";
    }

    // 追加或覆盖 lang 参数
    NSMutableArray<NSURLQueryItem *> *items = [components.queryItems mutableCopy] ?: [NSMutableArray array];
    NSInteger existingIndex = NSNotFound;
    for (NSInteger i = 0; i < items.count; i++) {
        NSURLQueryItem *item = items[i];
        if ([item.name isEqualToString:@"lang"]) {
            existingIndex = i;
            break;
        }
    }

    NSURLQueryItem *langItem = [NSURLQueryItem queryItemWithName:@"lang" value:lang];
    if (existingIndex != NSNotFound) {
        [items replaceObjectAtIndex:existingIndex withObject:langItem];
    } else {
        [items addObject:langItem];
    }

    components.queryItems = items;
    NSURL *url = components.URL;
    if (!url) { return; }

    NSArray *activityItems = @[url];
    UIActivityViewController *activityViewController =
        [[UIActivityViewController alloc] initWithActivityItems:activityItems applicationActivities:nil];

    activityViewController.completionWithItemsHandler = ^(UIActivityType  _Nullable activityType, BOOL completed, NSArray * _Nullable returnedItems, NSError * _Nullable activityError) {

        NSDictionary *params = @{
            @"completed" : @(completed),
            @"activityType" : activityType ? :@"notype"
        };

        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppShareIOSShareWindowClose data:params defaultHandler:nil];
        if (completed) {
            NSLog(@"用户完成了分享，分享渠道: %@", activityType);
            // 在这里处理分享成功后的逻辑，比如奖励金币
        } else {
            if (activityType == nil) {
                NSLog(@"用户点击了取消按钮，直接关闭了分享页");
            } else {
                NSLog(@"用户选择了分享渠道 %@，但最终取消了发送", activityType);
            }
        }

        if (activityError) {
            NSLog(@"分享出错: %@", activityError.localizedDescription);
        }
    };


    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    rootVc = rootVc.presentedViewController ?: rootVc;  // 使用当前呈现的视图控制器
    [rootVc presentViewController:activityViewController animated:YES completion:nil];
}


#pragma mark - events

- (void)show {
    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    rootVc = rootVc.presentedViewController ?: rootVc;  // 使用当前呈现的视图控制器
    [rootVc addChildViewController:self];
    [rootVc.view addSubview:self.view];
    [self.view layoutSubviews];
    [UIView animateWithDuration:0.01 animations:^{
        self.view.alpha = 1.0;
        self.containerView.transform = CGAffineTransformMakeTranslation(0, -(self.containerView.height - ZOOM(16)));
    }];
    // 显示之后记录下位置，方便后面滑动的移动
    self.originalContainerFrame = self.containerView.frame;
}

- (void)dismiss {
    UITabBarController *rootVc = (UITabBarController *)[WBAppManager getUIApplicationRootViewController];
    NSMutableArray *viewControllers = [NSMutableArray arrayWithArray:rootVc.childViewControllers];
    if ([viewControllers containsObject:self]) {    // 检查是否自动生成了新的tabBarItem，如果有就删除掉
        [viewControllers removeObject:self];
        rootVc.viewControllers = viewControllers;
    }

    [UIView animateWithDuration:0.5 animations:^{
        self.containerView.transform = CGAffineTransformMakeTranslation(0, self.containerView.height - ZOOM(16));
        self.view.alpha = 0;
    } completion:^(BOOL finished) {
        [self removeFromParentViewController];
        [self.view removeFromSuperview];
    }];
}

// 处理点击外部区域的回调方法
- (void)handleTapOutside:(UITapGestureRecognizer *)gesture {
    // 获取点击位置
    CGPoint location = [gesture locationInView:self.view];
    // 如果点击位置不在containerView内，则关闭弹出框
    if (location.y< WBScreenHeight - ZOOM(286)) {
        NSLog(@"dismiss Clicked");
        [self dismiss];
    }
}


/// 识别手势并作反应
- (void)handlePanGesture:(UIPanGestureRecognizer *)gestureRecognizer {

    CGPoint translation = [gestureRecognizer translationInView:self.view];
    CGFloat deltaY = translation.y;
    CGFloat threshold = ZOOM(50); // 假设ZOOM(10)返回一个合适的阈值
    switch (gestureRecognizer.state) {
        case UIGestureRecognizerStateBegan: {
            // 记录开始滑动时的位置
            self.initialTranslationY = deltaY;
            self.slidingTranslationY = deltaY;
            break;
        }
        case UIGestureRecognizerStateChanged: {
            // 更新弹出视图位置或透明度等属性
            CGFloat thisTimeDeltaY_real = deltaY - self.slidingTranslationY;
            if (thisTimeDeltaY_real<0) {// 向上滑动
                // 确保上滑时，containerView不会上移超过其初始高度
                CGRect newFrame = self.containerView.frame;
                newFrame.origin.y = self.containerView.frame.origin.y + thisTimeDeltaY_real;
                if(newFrame.origin.y > self.originalContainerFrame.origin.y){
                    self.containerView.frame = newFrame;
                }
            } else {// 向下滑动
                // 更新布局
                CGRect newFrame = self.containerView.frame;
                newFrame.origin.y = self.containerView.frame.origin.y + thisTimeDeltaY_real;
                self.containerView.frame = newFrame;
            }
            // 更新滑动触点位置
            self.slidingTranslationY = deltaY;
            break;
        }
        case UIGestureRecognizerStateEnded: {
            // 根据滑动距离决定是否关闭
            CGFloat totalDeltaY = fabs(deltaY - self.initialTranslationY);
            CGFloat velocityY = [gestureRecognizer velocityInView:self.view].y;
            if (deltaY < self.initialTranslationY) {// 向上滑动
                // 添加弹簧动画回弹
                [UIView animateWithDuration:0.3 delay:0 usingSpringWithDamping:0.7 initialSpringVelocity:velocityY/1000 options:0 animations:^{
                    self.containerView.frame = self.originalContainerFrame;
                } completion:nil];
            } else {// 向下滑动
                // 判断滑动距离是否满足关闭条件
                if (totalDeltaY >= threshold) {
                    [self dismiss]; // 关闭底部栏
                } else {
                    // 添加弹簧动画回弹
                    [UIView animateWithDuration:0.3 delay:0 usingSpringWithDamping:0.7 initialSpringVelocity:velocityY/1000 options:0 animations:^{
                        self.containerView.frame = self.originalContainerFrame;
                    } completion:nil];
                }
            }
            break;
        }
        default:
            // 重置translation
            [gestureRecognizer setTranslation:CGPointZero inView:self.view];
            break;
    }
}



