+ (void)shareAppToOthers {
    NSString *urlString = WBSettingManager.sharedManager.ShareURL ?: @"";
    NSURLComponents *components = [NSURLComponents componentsWithString:urlString];
    if (!components) { return; }

    // 取系统当前首选语言，例如: ar-SA / en-US / zh-Hans-CN
    NSString *preferred = [NSLocale preferredLanguages].firstObject ?: @"en";
    NSString *lang = [[preferred componentsSeparatedByString:@"-"] firstObject].lowercaseString;
    if (lang.length == 0) {
        lang = @"en";
    }

    // 追加或覆盖 lang 参数
    NSMutableArray<NSURLQueryItem *> *items = [components.queryItems mutableCopy] ?: [NSMutableArray array];
    NSInteger existingIndex = NSNotFound;
    for (NSInteger i = 0; i < items.count; i++) {
        NSURLQueryItem *item = items[i];
        if ([item.name isEqualToString:@"lang"]) {
            existingIndex = i;
            break;
        }
    }

    NSURLQueryItem *langItem = [NSURLQueryItem queryItemWithName:@"lang" value:lang];
    if (existingIndex != NSNotFound) {
        [items replaceObjectAtIndex:existingIndex withObject:langItem];
    } else {
        [items addObject:langItem];
    }

    components.queryItems = items;
    NSURL *url = components.URL;
    if (!url) { return; }

    NSArray *activityItems = @[url];
    UIActivityViewController *activityViewController =
        [[UIActivityViewController alloc] initWithActivityItems:activityItems applicationActivities:nil];

    activityViewController.completionWithItemsHandler = ^(UIActivityType  _Nullable activityType, BOOL completed, NSArray * _Nullable returnedItems, NSError * _Nullable activityError) {

        NSDictionary *params = @{
            @"completed" : @(completed),
            @"activityType" : activityType ? :@"notype"
        };

        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppShareIOSShareWindowClose data:params defaultHandler:nil];
        if (completed) {
            NSLog(@"用户完成了分享，分享渠道: %@", activityType);
            // 在这里处理分享成功后的逻辑，比如奖励金币
        } else {
            if (activityType == nil) {
                NSLog(@"用户点击了取消按钮，直接关闭了分享页");
            } else {
                NSLog(@"用户选择了分享渠道 %@，但最终取消了发送", activityType);
            }
        }

        if (activityError) {
            NSLog(@"分享出错: %@", activityError.localizedDescription);
        }
