- (void)updateInviteLabel {
    NSNumber *dayCount = WBReferralManager.sharedManager.inviterRewardDuration ?: @0;
    BOOL hasCompletedShare = WBSettingManager.sharedManager.HasCompletedShare;
    NSString *suffix = NSLocalizedString(@"天", nil);
    NSString *dayStr = [NSString stringWithFormat:@" + %@ ", dayCount];
    NSMutableAttributedString *attrStr = [[NSMutableAttributedString alloc] init];
    UIColor *textColor = WBColorHex(0x24CF41);
    UIFont *smallFont = [UIFont systemFontOfSize:ZOOM(18) weight:UIFontWeightMedium];
    UIFont *largeFont = [UIFont systemFontOfSize:ZOOM(24) weight:UIFontWeightMedium];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:NSLocalizedString(hasCompletedShare ? @"邀请" : @"分享", nil) attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    if (hasCompletedShare) {
        [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:@" 1 " attributes:@{
            NSFontAttributeName: largeFont,
            NSForegroundColorAttributeName: textColor
        }]];

        [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:NSLocalizedString(@"位用户", nil) attributes:@{
            NSFontAttributeName: smallFont,
            NSForegroundColorAttributeName: textColor
        }]];
    }

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:dayStr attributes:@{
        NSFontAttributeName: largeFont,
        NSForegroundColorAttributeName: textColor
    }]];

    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:suffix attributes:@{
        NSFontAttributeName: smallFont,
        NSForegroundColorAttributeName: textColor
    }]];

    _toInviteLabel.attributedText = attrStr;
    _toInviteLabel.textAlignment = NSTextAlignmentNatural;
}

