    if (!_toInviteView) {
        _toInviteView = [[UIView alloc] init];
        _toInviteView.backgroundColor = WBColorHex(0xEAF9ED);
        _toInviteView.layer.cornerRadius = ZOOM(12);
        UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleInviteActionTap)];
        [_toInviteView addGestureRecognizer:tapGesture];
    }
    return _toInviteView;
}

- (UIImageView *)rewardsDurationImageView {
    if (!_rewardsDurationImageView) {
        NSString *durationImageName = [WBAppManager sharedManager].isRTL ? @"Home_duration_backImage_RTL" : @"Home_duration_backImage";
        _rewardsDurationImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:durationImageName]];
        _rewardsDurationImageView.userInteractionEnabled = YES;
        UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(gotoInvitePage)];
        [_rewardsDurationImageView addGestureRecognizer:tapGesture];
    }
    return _rewardsDurationImageView;
}

- (void)gotoInvitePage {
    NSLog(@"dianjichengg");
    if (kStringIsEmpty(WBSettingManager.sharedManager.Email)) {
        WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
        loginVC.loginSource = WBLoginSourceInvite;  // 标记为从邀请页面触发的登录
        WBMainViewController *mainVC = (WBMainViewController*)[WBAppManager getUIApplicationRootViewController];

        if (![mainVC isKindOfClass:[WBMainViewController class]]) return;

        UINavigationController *loginNav = [[UINavigationController alloc] initWithRootViewController:loginVC];
        loginNav.modalPresentationStyle = UIModalPresentationFullScreen;
        [mainVC presentViewController:loginNav animated:YES completion:nil];
    } else {
        if (!WBReferralManager.sharedManager.activityStart) {
